// ============================================
// 产品列表配置 - 在这里修改你的产品
// ============================================
const products = [
  {
    product_id: "001",
    product_name: "联想笔记本",
    prompt: "一台银色笔记本电脑，薄型设计，专业产品摄影，白色背景，4K高清",
    generate_video: true
  },
  {
    product_id: "002",
    product_name: "机械键盘",
    prompt: "一把黑色机械键盘，RGB灯光效果，电竞风格，专业产品摄影",
    generate_video: false
  },
  {
    product_id: "003",
    product_name: "无线鼠标",
    prompt: "一只白色无线鼠标，简约设计，人体工学，专业产品摄影",
    generate_video: true
  }
];

return products.map(p => ({ json: p }));

const input = $input.first().json;
const product = $('产品列表').item.json;

return {
  json: {
    product_id: product.product_id,
    product_name: product.product_name,
    prompt: product.prompt,
    success: input.success || false,
    image_url: input.image_url || '',
    video_url: input.video_url || '',
    error: input.error || input.error_message || ''
  }
};

// 获取所有处理结果
const items = $input.all();
const results = items.map(item => item.json);

// 统计
const total = results.length;
const success = results.filter(r => r.success).length;
const failed = total - success;

// 构建飞书消息
let message_text = `📊 批量生成完成\n\n`;
message_text += `✅ 成功: ${success}/${total}\n`;
message_text += `❌ 失败: ${failed}\n`;
message_text += `📈 成功率: ${total > 0 ? Math.round(success / total * 100) : 0}%\n\n`;
message_text += `--- 详细结果 ---\n`;

results.forEach((r, i) => {
  const status = r.success ? '✅' : '❌';
  message_text += `${i+1}. ${status} ${r.product_name}\n`;
  if (r.success && r.image_url) {
    message_text += `   图片: 已生成\n`;
  }
  if (r.video_url) {
    message_text += `   视频: 已生成\n`;
  }
  if (!r.success && r.error) {
    message_text += `   错误: ${r.error}\n`;
  }
});

return {
  json: {
    summary: { total, success, failed },
    results: results,
    feishu_message: {
      msg_type: 'text',
      content: { text: message_text }
    }
  }
};
